/** Mirrors the Rust `ChunkResult` struct returned by the export commands. */
export interface ChunkResult {
  index: number;
  prose: string;
  label?: string;
}

/** Mirrors the Rust `ExportStatus` struct. */
export interface ExportStatus {
  status: string;
  progress: number;
  output_path: string | null;
  current_chunk: number;
