/**
 * Parses game tags from AI responses — inventory mutations, skill changes,
 * level progression, faction reputation, and crafting tags.
 * 
 * Inventory tags:
 *   [INV:+item_name]              — add item (qty 1)
 *   [INV:-item_name]              — remove item
 *   [INV:+n:item_name]            — add n items
 *   [INV:-n:item_name]            — remove n items
 * 
 * Skill tags:
 *   [SKILL:+name]                 — learn new skill (level 1)
 *   [SKILL:+name:level]           — learn skill at given level
 *   [SKILL:name+n]                — increase skill by n levels
 *   [SKILL:name-n]                — decrease skill by n levels
 * 
 * Level tags:
 *   [LEVEL:+xp]                   — add XP (e.g. [LEVEL:+50])
 *   [LEVEL:+level]                — increase level by 1 (e.g. [LEVEL:+1])
 * 
 * Faction tags:
 *   [FACTION:+name:delta]         — adjust reputation by delta (or create at delta)
 *   [FACTION:name]                — show current reputation (no-op in parsing)
 * 
 * Crafting tags:
 *   [CRAFT:result_name:ingredient1+ingredient2]  — discover recipe (consumes ingredients)
 *   [CRAFTED:result_name]                        — craft item (perks auto by skill)
 *   [CRAFTED:result_name:perk1+perk2]            — craft item with specific perks
 * 
 * Returns the cleaned text (all tags removed) and parsed mutations.
 */
export interface InvMutation {
  op: "add" | "remove";
  item: string;
  qty: number;
}

export interface SkillMutation {
  name: string;
  /** Positive = increase, negative = decrease, 0 = set absolute */
  delta: number;
  absolute: number | null; // used for [SKILL:+name:level]
}

export interface LevelMutation {
  xpDelta: number;
  levelDelta: number;
}

export interface ConditionMutation { op: "add" | "remove"; name: string; description?: string; duration?: string; }

export interface CraftMutation {
  /** Result item name (what this recipe produces). */
  resultItem: string;
  /** List of ingredient names consumed by the recipe. */
  ingredients: string[];
}

export interface CraftedMutation {
  /** Result item name (what was successfully crafted). */
  resultItem: string;
  /** Specific perks chosen by the AI. Empty when perks should be auto-filled. */
  perks: string[];
}

export interface FactionMutation {
  /** Faction name (lowercased for matching). */
  name: string;
  /** Reputation delta (positive = gain, negative = loss). 0 for show-only. */
  delta: number;
  /** True when the tag is just [FACTION:name] (show-only, no mutation). */
  showOnly: boolean;
}

interface ParsedTags {
  cleanText: string;
  mutations: InvMutation[];
  skillChanges: SkillMutation[];
  levelChanges: LevelMutation[];
  factionMutations: FactionMutation[];
  craftMutations: CraftMutation[];
  craftedMutations: CraftedMutation[];
}

export function parseGameTags(text: string): ParsedTags {
  const mutations: InvMutation[] = [];
  const skillChanges: SkillMutation[] = [];
  const levelChanges: LevelMutation[] = [];
  const factionMutations: FactionMutation[] = [];
  const craftMutations: CraftMutation[] = [];
  const craftedMutations: CraftedMutation[] = [];

  let cleanText = text;

  // Parse inventory tags: [INV:+/-item]
  cleanText = cleanText.replace(/\[INV:([+-])(\d+:)?([^\]]+)\]/gi, (_m, op: string, qtyPrefix: string | undefined, item: string) => {
    let qty = 1;
    if (qtyPrefix) {
      const n = parseInt(qtyPrefix.replace(":", ""), 10);
      if (!isNaN(n) && n > 0) qty = n;
    }
    mutations.push({ op: op === "+" ? "add" : "remove", item: item.trim(), qty });
    return "";
  });

  // Parse skill tags:
  //   [SKILL:+name] or [SKILL:+name:level]
  //   [SKILL:name+n] or [SKILL:name-n]
  cleanText = cleanText.replace(/\[SKILL:([+-])([^+\-\]:]+)(?::(\d+))?\]/gi, (_m, op: string, name: string, levelStr?: string) => {
    const absolute = levelStr ? parseInt(levelStr, 10) : null;
    skillChanges.push({
      name: name.trim(),
      delta: op === "+" ? 1 : -1,
      absolute,
    });
    return "";
  });

  // Also handle relative: [SKILL:name+n] or [SKILL:name-n]
  cleanText = cleanText.replace(/\[SKILL:([^+\-\]]+)([+-])(\d+)\]/gi, (_m, name: string, op: string, nStr: string) => {
    skillChanges.push({
      name: name.trim(),
      delta: op === "+" ? parseInt(nStr, 10) : -parseInt(nStr, 10),
      absolute: null,
    });
    return "";
  });

  // Parse level tags: [LEVEL:+xp]
  cleanText = cleanText.replace(/\[LEVEL:\+(\d+)\]/gi, (_m, nStr: string) => {
    const n = parseInt(nStr, 10);
    if (!isNaN(n) && n > 0) {
      levelChanges.push({ xpDelta: n, levelDelta: 0 });
    }
    return "";
  });

  // Parse faction tags:
  //   [FACTION:+name:delta] or [FACTION:-name:delta] — adjust reputation
  //   [FACTION:name]                             — show-only
  cleanText = cleanText.replace(/\[FACTION:([+-]?)([^+\-\]:]+?)(?::(-?\d+))?\]/gi, (_m, op: string, name: string, deltaStr?: string) => {
    const trimmedName = name.trim();
    if (!op && !deltaStr) {
      // [FACTION:name] — show only, no mutation
      factionMutations.push({ name: trimmedName, delta: 0, showOnly: true });
    } else {
      const delta = deltaStr ? parseInt(deltaStr, 10) : 0;
      if (delta !== 0) {
        factionMutations.push({ name: trimmedName, delta, showOnly: false });
      }
    }
    return "";
  });

  // Parse CRAFTED tags first (more specific) before CRAFT tags:
  //   [CRAFTED:result_name]              — crafted with auto perks
  //   [CRAFTED:result_name:perk1+perk2]  — crafted with specific perks
  cleanText = cleanText.replace(/\[CRAFTED:([^:\]]+?)(?::([^:\]]+?))?\]/gi, (_m, resultItem: string, perksStr?: string) => {
    const perks = perksStr
      ? perksStr.split("+").map((p) => p.trim()).filter(Boolean)
      : [];
    craftedMutations.push({ resultItem: resultItem.trim(), perks });
    return "";
  });

  // Parse CRAFT tags:
  //   [CRAFT:result_name:ingredient1+ingredient2]  — discover recipe
  cleanText = cleanText.replace(/\[CRAFT:([^:\]]+?):([^:\]]+?)\]/gi, (_m, resultItem: string, ingredientsStr: string) => {
    const ingredients = ingredientsStr.split("+").map((i) => i.trim()).filter(Boolean);
    if (ingredients.length > 0) {
      craftMutations.push({ resultItem: resultItem.trim(), ingredients });
    }
    return "";
  });

  return { cleanText, mutations, skillChanges, levelChanges, factionMutations, craftMutations, craftedMutations };
}

import type { Persona } from "../db/repositories/personasRepo";
import { updatePersona, updatePersonaXpLevel } from "../db/repositories/personasRepo";
import { createFaction, listFactions, updateReputation } from "../db/repositories/factionsRepo";
import { createRecipe, getRecipeByResult, updateRecipePerks } from "../db/repositories/craftingRepo";
import { parseGameTags } from "./inventoryTags";

/** Parses game tags (inventory + skill + level + faction) from the AI response,
 *  updates the persona in DB, and returns the cleaned text. */
export async function processGameResponse(
  persona: Persona | null,
  text: string,
  _chatId?: string,
): Promise<string> {
  if (!persona) return text;
  const { cleanText, mutations, skillChanges, levelChanges, factionMutations, craftMutations, craftedMutations } = parseGameTags(text);
  if (mutations.length === 0 && skillChanges.length === 0 && levelChanges.length === 0 && factionMutations.length === 0 && craftMutations.length === 0 && craftedMutations.length === 0) return text;

  // Apply inventory mutations
  const inv = persona.inventory ? [...persona.inventory.map((i) => ({ ...i }))] : [];
  for (const m of mutations) {
    const existing = inv.find((i) => i.item.toLowerCase() === m.item.toLowerCase());
    if (m.op === "add") {
      if (existing) {
        existing.qty += m.qty;
      } else {
        inv.push({ item: m.item, qty: m.qty });
      }
    } else {
      if (existing) {
        existing.qty -= m.qty;
        if (existing.qty <= 0) inv.splice(inv.indexOf(existing), 1);
      }
    }
  }

  // Apply skill mutations
  const skills = persona.skills ? [...persona.skills.map((s) => ({ ...s }))] : [];
  for (const s of skillChanges) {
    const existing = skills.find((sk) => sk.name.toLowerCase() === s.name.toLowerCase());
    if (s.absolute !== null) {
      // Absolute set: [SKILL:+name:3]
      if (existing) {
        existing.level = s.absolute;
      } else {
        skills.push({ name: s.name, level: s.absolute });
      }
    } else if (s.delta > 0) {
      // Relative increase: [SKILL:name+2] or [SKILL:+name]
      if (existing) {
        existing.level += s.delta;
      } else {
        skills.push({ name: s.name, level: s.delta });
      }
    } else {
      // Decrease: [SKILL:name-1] — remove if <= 0
      if (existing) {
        existing.level = Math.max(0, existing.level + s.delta);
        if (existing.level <= 0) skills.splice(skills.indexOf(existing), 1);
      }
    }
  }

  // Apply level mutations
  let xp = persona.xp ?? 0;
  let level = persona.level ?? 1;
  let hasLevelChanges = false;
  for (const lc of levelChanges) {
    if (lc.xpDelta > 0) { xp += lc.xpDelta; hasLevelChanges = true; }
    if (lc.levelDelta > 0) { level += lc.levelDelta; hasLevelChanges = true; }
  }

  // Apply faction mutations
  for (const fm of factionMutations) {
    if (fm.showOnly) continue; // show-only tags are no-ops at processing time
    try {
      const existing = await listFactions(persona.id);
      const match = existing.find(
        (f) => f.factionName.toLowerCase() === fm.name.toLowerCase(),
      );
      if (match) {
        await updateReputation(match.id, fm.delta);
      } else {
        await createFaction(persona.id, fm.name, fm.delta);
      }
    } catch {
      // Non-critical
    }
  }

  // Apply craft mutations: [CRAFT:result:ingredient1+ingredient2]
  for (const cm of craftMutations) {
    try {
      // Create the recipe in DB (or skip if already known)
      const existing = await getRecipeByResult(persona.id, cm.resultItem);
      if (!existing) {
        // Determine tier based on skill level (AI may set later, default 0)
        const relatedSkill = persona.skills?.find(
          (s) => cm.ingredients.some((ing) =>
            ing.toLowerCase().includes(s.name.toLowerCase().slice(0, 4)) ||
            s.name.toLowerCase().includes("alchymie")
          )
        );
        // Try to infer skill name from context (default "Alchymie" for potions, "Kovářství" for weapons)
        let inferredSkill = relatedSkill?.name ?? null;
        if (!inferredSkill && cm.resultItem.toLowerCase().includes("lektvar")) inferredSkill = "Alchymie";
        else if (!inferredSkill && cm.resultItem.toLowerCase().includes("jed")) inferredSkill = "Alchymie";
        else if (!inferredSkill) inferredSkill = "Kovářství";

        await createRecipe({
          personaId: persona.id,
          resultItem: cm.resultItem,
          ingredients: cm.ingredients,
          skillName: inferredSkill,
          tier: 0,
        });
      }
      // Consume ingredients from inventory (always consumed, even on failure)
      for (const ing of cm.ingredients) {
        const entry = inv.find((i) => i.item.toLowerCase() === ing.toLowerCase());
        if (entry) {
          entry.qty -= 1;
          if (entry.qty <= 0) inv.splice(inv.indexOf(entry), 1);
        }
      }
    } catch {
      // Non-critical
    }
  }

  // Apply crafted mutations: [CRAFTED:result] or [CRAFTED:result:perk1+perk2]
  for (const cdm of craftedMutations) {
    try {
      // Add the crafted item to inventory
      const existingItem = inv.find((i) => i.item.toLowerCase() === cdm.resultItem.toLowerCase());
      if (existingItem) {
        existingItem.qty += 1;
      } else {
        inv.push({ item: cdm.resultItem, qty: 1 });
      }
      // Update the recipe's perks
      const recipe = await getRecipeByResult(persona.id, cdm.resultItem);
      if (recipe) {
        await updateRecipePerks(recipe.id, cdm.perks);
      }
    } catch {
      // Non-critical
    }
  }

  try {
    await updatePersona(persona.id, {
      name: persona.name,
      gender: persona.gender,
      age: persona.age,
      race: persona.race,
      appearance: persona.appearance,
      progression: persona.progression,
      skills,
      inventory: inv,
    });
    if (hasLevelChanges) {
      await updatePersonaXpLevel(persona.id, xp, level);
    }
  } catch {
    // Non-critical
  }

  return cleanText;
}

import { execute, newId, nowIso, query } from "../database";

export interface CraftingRecipe {
  id: string;
  personaId: string;
  resultItem: string;
  ingredients: string[];
  skillName: string | null;
  tier: number;
  perks: string[];
  description: string | null;
  craftedAt: string | null;
}

interface CraftingRecipeRow {
  id: string;
  persona_id: string;
  result_item: string;
  ingredients: string; // JSON array of strings
  skill_name: string | null;
  tier: number;
  perks: string; // JSON array of strings
  description: string | null;
  crafted_at: string | null;
}

function parseJsonArray(raw: string): string[] {
  try {
    return JSON.parse(raw) as string[];
  } catch {
    return [];
  }
}

function toCraftingRecipe(row: CraftingRecipeRow): CraftingRecipe {
  return {
    id: row.id,
    personaId: row.persona_id,
    resultItem: row.result_item,
    ingredients: parseJsonArray(row.ingredients),
    skillName: row.skill_name,
    tier: row.tier,
    perks: parseJsonArray(row.perks),
    description: row.description,
    craftedAt: row.crafted_at,
  };
}

/** List all recipes for a persona, ordered by tier descending, then by result name. */
export async function listRecipes(personaId: string): Promise<CraftingRecipe[]> {
  const rows = await query<CraftingRecipeRow>(
    `SELECT * FROM crafting_recipes WHERE persona_id = $1
     ORDER BY tier DESC, result_item ASC`,
    [personaId],
  );
  return rows.map(toCraftingRecipe);
}

/** Get a single recipe by result item name (case-insensitive). */
export async function getRecipeByResult(
  personaId: string,
  resultItem: string,
): Promise<CraftingRecipe | null> {
  const rows = await query<CraftingRecipeRow>(
    "SELECT * FROM crafting_recipes WHERE persona_id = $1 AND LOWER(result_item) = LOWER($2)",
    [personaId, resultItem],
  );
  return rows[0] ? toCraftingRecipe(rows[0]) : null;
}

export interface CreateRecipeInput {
  personaId: string;
  resultItem: string;
  ingredients: string[];
  skillName?: string;
  tier?: number;
  description?: string;
}

/** Create a new crafting recipe (not yet crafted — perks and craftedAt are empty). */
export async function createRecipe(input: CreateRecipeInput): Promise<CraftingRecipe> {
  const id = newId();
  const now = nowIso();
  await execute(
    `INSERT INTO crafting_recipes (id, persona_id, result_item, ingredients, skill_name, tier, perks, description, crafted_at)
     VALUES ($1, $2, $3, $4, $5, $6, '[]', $7, NULL)`,
    [
      id,
      input.personaId,
      input.resultItem,
      JSON.stringify(input.ingredients),
      input.skillName ?? null,
      input.tier ?? 0,
      input.description ?? null,
    ],
  );
  return {
    id,
    personaId: input.personaId,
    resultItem: input.resultItem,
    ingredients: input.ingredients,
    skillName: input.skillName ?? null,
    tier: input.tier ?? 0,
    perks: [],
    description: input.description ?? null,
    craftedAt: null,
  };
}

/** Update a recipe's perks and set crafted_at when the item is crafted. */
export async function updateRecipePerks(
  id: string,
  perks: string[],
): Promise<void> {
  const now = nowIso();
  await execute(
    `UPDATE crafting_recipes SET perks = $2, crafted_at = $3 WHERE id = $1`,
    [id, JSON.stringify(perks), now],
  );
}

